// The paint phase walks the render tree, calling paint() on each RenderObject.
// A RenderObject that has isRepaintBoundary=true (or is wrapped in a
// RepaintBoundary widget) paints to its OWN compositing LAYER.

RepaintBoundary(
  child: AnimatedContainer(
    duration: Duration(milliseconds: 300),
    color: color,
    child: /* expensive subtree */,
  ),
)

// Effect: when the color changes and only this AnimatedContainer needs to
// repaint, Flutter re-records its layer WITHOUT touching neighboring layers.
// The compositor blends the (unchanged) neighbors + (updated) layer on GPU.
// This is a huge win when you have a big list scrolling next to a static header.

// See it in DevTools: 'Highlight Repaints' ã layers turn different colors when
// they re-record. If layers you didn't expect are flashing, wrap them in a
// RepaintBoundary.

import 'package:flutter/material.dart';
import 'package:flutter/rendering.dart';

void main() => runApp(MaterialApp(home: Scaffold(
  appBar: AppBar(title: const Text('Custom RenderBox')),
  body: const Center(child: PulseBox(color: Colors.deepPurple, size: 200)),
)));

// A widget backed by a custom RenderObject that paints a filled square.
// This is the same pattern used by every leaf widget in Flutter (Text, Image,
// ColoredBox, RawImage) ã a RenderObjectWidget wrapping a RenderBox.
class PulseBox extends LeafRenderObjectWidget {
  const PulseBox({super.key, required this.color, required this.size});
  final Color color;
  final double size;

  @override
  RenderObject createRenderObject(BuildContext context) =>
      _RenderPulseBox(color: color, side: size);

  @override
  void updateRenderObject(BuildContext context, _RenderPulseBox render) {
    render
      ..color = color
      ..side = size;
  }
}

class _RenderPulseBox extends RenderBox {
  _RenderPulseBox({required Color color, required double side})
    : _color = color, _side = side;

  Color _color;
  double _side;
  set color(Color v) { if (_color == v) return; _color = v; markNeedsPaint(); }
  set side(double v) { if (_side == v) return; _side = v; markNeedsLayout(); }

  @override
  void performLayout() {
    // Constraints flow DOWN ã we must respect them.
    size = constraints.constrain(Size(_side, _side));
  }

  @override
  void paint(PaintingContext ctx, Offset offset) {
    final rect = offset & size;
    ctx.canvas.drawRect(rect, Paint()..color = _color);
  }

  @override
  bool hitTestSelf(Offset position) => true;   // consume taps
}

// This is exactly how RenderObject internals work throughout Flutter.
// Notice the pattern: setters call markNeedsPaint or markNeedsLayout,
// invalidating the correct pipeline stage. Flutter re-runs only what's dirty.
